#!/usr/bin/env python3
from pathlib import Path
import json, re, shutil
APP=Path(__file__).resolve().parents[1]
BANK_ROOT=APP/'data/observation_banks/creative_arts/worlds/digital_art'
SUB_ROOT=BANK_ROOT/'subcategories'
RUNTIME_DIR=APP/'data/content/base_bundle/creative_arts/digital_art'

def sid(s): return re.sub(r'[^a-z0-9]+','_',s.lower()).strip('_')
def diff(i): return ('beginner',1) if i<40 else (('intermediate',2) if i<70 else (('advanced',3) if i<90 else ('expert',4)))
def distract(term,pool):
    out=[]
    for x,_ in pool:
        if x!=term and x not in out: out.append(x)
        if len(out)>=3: break
    while len(out)<3: out.append('Not '+term)
    return out
