def build_trans(term, wrongs, prompt):
    return {m:{'prompt':prompt,'correct_answer':term,'wrong_answers':wrongs} for m in mechs}
SUB_ROOT.mkdir(parents=True,exist_ok=True)
if RUNTIME_DIR.exists(): shutil.rmtree(RUNTIME_DIR)
RUNTIME_DIR.mkdir(parents=True,exist_ok=True)
wm_path=BANK_ROOT/'world_manifest.json'; wm=json.load(open(wm_path))
for sc in wm['subcategories']: sc.update({'implemented_observations':100,'status':'complete','scenario_preferences':prefs})
wm['status']='complete'; json.dump(wm,open(wm_path,'w'),indent=2)
compiled=[]
for subname,pool in subcats.items():
    subid=sid(subname); obs=[]
    for i in range(100):
        term,clue=pool[i%len(pool)]; wrongs=distract(term,pool); label,tier=diff(i); oid=f'creative_arts_digital_art_{subid}_{i+1:04d}'; variant=i//len(pool)
        prompt=[f'Which {subname} term matches: {clue}?',f'In {subname}, what means {clue}?',f'Name the {subname} concept described as: {clue}.',f'Which {subname.lower()} term is {clue}?'][variant%4]
        knowledge={'domain':'digital_art','subcategory':subid,'term':term,'concept':term,'definition_clue':clue,'recognized_answer':term,'distractor_family':wrongs,'difficulty_tier':tier,'keywords':[subid,sid(term)],'prompt_variant':variant}
        transformations=build_trans(term,wrongs,prompt)
        obs.append({'observation_id':oid,'universe':'creative_arts','world':'digital_art','subcategory':subid,'difficulty':{'label':label,'tier':tier},'observation_type':'Rapid Recognition','base_fact':f'{term}: {clue}.','prompt':prompt,'correct_answer':term,'distractors':wrongs,'localization':{'prompt_key':oid+'_prompt','answer_key':oid+'_answer'},'knowledge':knowledge,'mechanic_transformations':transformations,'metadata':{'tags':knowledge['keywords'],'scenario_compatibility':prefs,'deterministic_seed_key':oid,'quality':{'recognition':5,'visual_presentation':5,'fast_comprehension':5,'replayability':5,'educational_value':5,'mobile_readability':5},'source_basis':'Digital art education reference set based on production fundamentals.','knowledge':knowledge,'mechanic_transformations':transformations}})
        for mech,rule in transformations.items(): compiled.append({'id':f'{oid}_{mech}','observation_id':oid,'universe':'creative_arts','world':'digital_art','subcategory':subid,'type':mech,'rules':{'prompt':prompt,'legacy_prompt':prompt,'correct_answer':term,'wrong_answers':wrongs},'presentation':{'title':f'Digital Art — {subname}','difficulty_tier':tier,'subcategory':subid,'observation_type':mech},'knowledge':knowledge,'metadata':{'source_observation_id':oid,'knowledge':knowledge,'mechanic_transformations':transformations,'built_by':'digital_art_state_machine_compiler'}})
    bank={'schema_version':1,'observation_bank_version':'creative_arts.v1.digital_art','universe':'creative_arts','world':'digital_art','subcategory':subid,'display_name':subname,'constraint_vector':{'core_concept_space':f'Digital art concepts bounded to {subname}.','allowed_elements':['digital art vocabulary','tools','workflows','visual production concepts'],'forbidden_elements':['temporary platform trends','unverified software rumors','celebrity gossip','opinion-only prompts'],'domain_anchors':['digital art production fundamentals','game and media art pipelines','visual design education vocabulary'],'mechanic_suitability_map':prefs},'scenario_preferences':prefs,'observations':obs}
    json.dump(bank,open(SUB_ROOT/f'{subid}.json','w'),indent=2,ensure_ascii=False)
json.dump(compiled,open(RUNTIME_DIR/'digital_art_observation_bank_compiled.json','w'),indent=2,ensure_ascii=False)
print('digital_art observations',sum(len(json.load(open(p))['observations']) for p in SUB_ROOT.glob('*.json')),'compiled',len(compiled))
